1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (liveNeighbors === 2 && isAlive);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const aliveKeys = new Set(cells.map(cellKey));
19	  const candidates = new Map<string, Cell>();
20	  const counts = new Map<string, number>();
21	
22	  for (const cell of cells) {
23	    for (const neighbor of neighborsOf(cell)) {
24	      const key = cellKey(neighbor);
25	      candidates.set(key, neighbor);
26	      counts.set(key, (counts.get(key) ?? 0) + 1);
27	    }
28	  }
29	
30	  return [...candidates].flatMap(([key, cell]) =>
31	    survives(aliveKeys.has(key), counts.get(key) ?? 0) ? [cell] : []
32	  );
33	}
