1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it.todo("kills two adjacent live cells (each has only 1 neighbor)");
12	  it("keeps a live cell alive when it has 2 live neighbors (survival)", () => {
13	    // Three in a row: center (0,0) has 2 neighbors (-1,0) and (1,0) and survives
14	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
15	    const keys = new Set(result.map((c) => c.join(",")));
16	    expect(keys.has("0,0")).toBe(true);
17	  });
18	  it("keeps a live cell alive when it has 3 live neighbors (survival)", () => {
19	    // (0,0) has 3 neighbors: (1,0), (0,1), (1,1)
20	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
21	    const keys = new Set(result.map((c) => c.join(",")));
22	    expect(keys.has("0,0")).toBe(true);
23	  });
24	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
25	    // Center (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,2)
26	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2]]);
27	    const keys = new Set(result.map((c) => c.join(",")));
28	    expect(keys.has("1,1")).toBe(false);
29	  });
30	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
31	    // L-shape: (0,0), (1,0), (0,1) → dead cell (1,1) has 3 neighbors
32	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
33	    const keys = new Set(result.map((c) => c.join(",")));
34	    expect(keys.has("1,1")).toBe(true);
35	  });
36	  it("transforms a vertical blinker into a horizontal blinker", () => {
37	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
38	    const result = nextGeneration(vertical);
39	    const keys = new Set(result.map((c) => c.join(",")));
40	    expect(keys).toEqual(new Set(["-1,1", "0,1", "1,1"]));
41	    expect(result.length).toBe(3);
42	  });
43	  it("keeps a block (still life) unchanged", () => {
44	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
45	    const result = nextGeneration(block);
46	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
47	      new Set(block.map((c) => c.join(",")))
48	    );
49	    expect(result.length).toBe(4);
50	  });
51	  it.todo("handles negative coordinates correctly");
52	});
