export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const candidates = new Map<string, { cell: Cell; liveNeighbors: number }>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = candidates.get(key);
      if (entry) {
        entry.liveNeighbors += 1;
      } else {
        candidates.set(key, { cell: neighbor, liveNeighbors: 1 });
      }
    }
  }

  return [...candidates]
    .filter(([key, { liveNeighbors }]) => survives(aliveKeys.has(key), liveNeighbors))
    .map(([, { cell }]) => cell);
}

